import React from 'react';
import styles from './VoucherPagerNav.module.css';

export interface VoucherPagerNavProps {
  index: number;
  total: number;
  onFirst: () => void;
  onPrev: () => void;
  onNext: () => void;
  onEnd: () => void;
  testIdPrefix: string;
  className?: string;
}

export const VoucherPagerNav: React.FC<VoucherPagerNavProps> = ({
  index,
  total,
  onFirst,
  onPrev,
  onNext,
  onEnd,
  testIdPrefix,
  className,
}) => {
  const atStart = index <= 0;
  const atEnd = index >= total - 1;

  return (
    <div
      className={[styles.navGroup, className].filter(Boolean).join(' ')}
      data-testid={`${testIdPrefix}-nav`}
    >
      <button type="button" className={styles.navBtn} data-testid={`${testIdPrefix}-first`} onClick={onFirst} disabled={atStart} title="Đầu">
        <i className="fas fa-angle-double-left" aria-hidden />
      </button>
      <button type="button" className={styles.navBtn} data-testid={`${testIdPrefix}-prev`} onClick={onPrev} disabled={atStart} title="Trước">
        <i className="fas fa-angle-left" aria-hidden />
      </button>
      <span className={styles.navPosition} data-testid={`${testIdPrefix}-position`}>
        {index + 1}/{total}
      </span>
      <button type="button" className={styles.navBtn} data-testid={`${testIdPrefix}-next`} onClick={onNext} disabled={atEnd} title="Sau">
        <i className="fas fa-angle-right" aria-hidden />
      </button>
      <button type="button" className={styles.navBtn} data-testid={`${testIdPrefix}-end`} onClick={onEnd} disabled={atEnd} title="Cuối">
        <i className="fas fa-angle-double-right" aria-hidden />
      </button>
    </div>
  );
};
